import{c as t,Q as o,j as a,m as r}from"./chunks/framework.BA1dEi98.js";const s="/librislog/next/screenshots/missing-covers.png",m=JSON.parse('{"title":"Missing Covers Workflow","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/missing-covers.md","filePath":"guide/using-librislog/missing-covers.md","lastUpdated":1780166664000}'),i={name:"guide/using-librislog/missing-covers.md"};function n(d,e,l,c,h,g){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="missing-covers-workflow" tabindex="-1">Missing Covers Workflow <a class="header-anchor" href="#missing-covers-workflow" aria-label="Permalink to &quot;Missing Covers Workflow&quot;">​</a></h1><p>The Missing Covers page provides a streamlined, one-book-at-a-time workflow for assigning book covers to books missing them. It&#39;s accessible from <strong>Profile → Manage my data → Manage Missing Covers</strong>.</p><p><img src="'+s+'" alt="Missing Covers workflow" loading="lazy"></p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><p>The page shows one book at a time along with auto-searched cover candidates and manual options.</p><h3 id="cover-candidates" tabindex="-1">Cover Candidates <a class="header-anchor" href="#cover-candidates" aria-label="Permalink to &quot;Cover Candidates&quot;">​</a></h3><p>If the book has an ISBN, the page automatically searches multiple cover sources (AbeBooks, Open Library, Amazon, Hardcover) and displays results in a resolution-sorted grid. Click a candidate to save it as the book&#39;s cover — the app downloads the image, stores it locally, and immediately advances to the next book.</p><h3 id="no-isbn-or-no-candidates" tabindex="-1">No ISBN or No Candidates <a class="header-anchor" href="#no-isbn-or-no-candidates" aria-label="Permalink to &quot;No ISBN or No Candidates&quot;">​</a></h3><p>If the book has no ISBN or no cover candidates were found, the page shows:</p><ul><li><strong>Search Cover on Google</strong> — opens a Google image search for the book in a new tab</li><li><strong>Manual URL input</strong> — paste a direct image URL and click <strong>Save Cover</strong></li></ul><h3 id="skip" tabindex="-1">Skip <a class="header-anchor" href="#skip" aria-label="Permalink to &quot;Skip&quot;">​</a></h3><p>Click <strong>Skip</strong> to move past the current book without saving a cover. Skipped books remain in the missing-covers count.</p><h3 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>1</code>–<code>9</code></td><td>Select the N-th cover candidate</td></tr><tr><td><code>→</code> (Arrow Right)</td><td>Skip current book</td></tr></tbody></table><h2 id="all-done" tabindex="-1">All Done <a class="header-anchor" href="#all-done" aria-label="Permalink to &quot;All Done&quot;">​</a></h2><p>When all missing covers have been assigned, a success message is shown with a link back to the library.</p><h2 id="difference-from-data-hygiene" tabindex="-1">Difference from Data Hygiene <a class="header-anchor" href="#difference-from-data-hygiene" aria-label="Permalink to &quot;Difference from Data Hygiene&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Data Hygiene</th><th>Missing Covers</th></tr></thead><tbody><tr><td><strong>Scope</strong></td><td>Any missing metadata (author, ISBN, cover, etc.)</td><td>Covers only</td></tr><tr><td><strong>Interaction model</strong></td><td>Table with checkboxes, batch updates</td><td>One book at a time, immediate save</td></tr><tr><td><strong>Auto-suggestions</strong></td><td>None</td><td>Auto-searches cover candidates by ISBN</td></tr><tr><td><strong>Speed optimization</strong></td><td>Paginated list (50/page)</td><td>Prefetch next book + candidates; keyboard shortcuts</td></tr><tr><td><strong>Entry point</strong></td><td>Profile → Data Hygiene</td><td>Profile → Manage Missing Covers</td></tr><tr><td><strong>Success feedback</strong></td><td>Batch toast</td><td>Per-book toast + auto-advance</td></tr></tbody></table>',18)])])}const p=t(i,[["render",n]]);export{m as __pageData,p as default};
